mapper.insert:
INSERT INTO report          /* 신고 테이블 */
(   
    user_id                 /* 회원 키( 신고자 ) */
  , obj_id                  /* 대상 ID */
  , obj_type                /* 대상 타입 */
  , reason_code             /* 신고 사유 코드 */
  , status_code             /* 신고 상태 코드 */
  , created_at              /* 등록 일시 */
)
VALUES
(
    #{userId}
  , #{objId}
  , #{objType}
  , #{reasonCode}
  , 'RECEIVED'
  , NOW()
)

mapper.select:
SELECT COUNT(*)
  FROM report           /* 신고 테이블 */
 WHERE user_id = #{userId}
   AND obj_id = #{objId}
   AND obj_type = #{objType}
   AND is_deleted = 'N'
